import{_ as o,o as r,c as a,ai as e}from"./chunks/framework.DMjte4z8.js";const q=JSON.parse('{"title":"单位编辑器详解","description":"","frontmatter":{"title":"单位编辑器详解","category":"object-editor","updated":"2026-05-08T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://en.wikipedia.org/wiki/Warcraft_III:_Reign_of_Chaos","https://www.youtube.com/watch?v=fYdtgSdYw3E","https://world-editor-tutorials.thehelper.net/","https://warcraft.wiki.gg/wiki/Warcraft_III_World_Editor"]},"headers":[],"relativePath":"object-editor/单位编辑器详解.md","filePath":"object-editor/单位编辑器详解.md","lastUpdated":1778216780000}'),l={name:"object-editor/单位编辑器详解.md"};function n(i,t,s,g,d,u){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="单位编辑器详解" tabindex="-1">单位编辑器详解 <a class="header-anchor" href="#单位编辑器详解" aria-label="Permalink to “单位编辑器详解”">​</a></h1><h2 id="单位编辑器基础入门" tabindex="-1">单位编辑器基础入门 <a class="header-anchor" href="#单位编辑器基础入门" aria-label="Permalink to “单位编辑器基础入门”">​</a></h2><p>在本节中，你将学习什么是单位编辑器，以及如何打开和使用它的基础界面。学完本节后，你将能够独立打开单位编辑器，并认识界面上各个区域的名字和作用。</p><h3 id="什么是单位编辑器" tabindex="-1">什么是单位编辑器 <a class="header-anchor" href="#什么是单位编辑器" aria-label="Permalink to “什么是单位编辑器”">​</a></h3><p>单位编辑器（Object Editor）是魔兽争霸3世界编辑器（World Editor，简称WE）中用于<strong>创建和修改游戏单位</strong>的工具[^2]。你可以用它来设置一个士兵的攻击力、生命值、移动速度等属性，也可以创建全新的英雄或怪物。简单来说，单位编辑器就是定义&quot;游戏里有什么角色&quot;的地方。</p><h3 id="打开单位编辑器的两种方法" tabindex="-1">打开单位编辑器的两种方法 <a class="header-anchor" href="#打开单位编辑器的两种方法" aria-label="Permalink to “打开单位编辑器的两种方法”">​</a></h3><h4 id="方法一-菜单打开" tabindex="-1">方法一：菜单打开 <a class="header-anchor" href="#方法一-菜单打开" aria-label="Permalink to “方法一：菜单打开”">​</a></h4><ol><li>启动 <strong>World Editor.exe</strong>（在魔兽争霸3安装目录下的 <code>World Editor.exe</code>）</li><li>在顶部菜单栏找到 <strong>&quot;模块&quot;</strong>（Modules）菜单</li><li>点击下拉菜单中的 <strong>&quot;对象编辑器&quot;</strong>（Object Editor）</li><li>在对象编辑器窗口中，点击左侧分类栏的 <strong>&quot;单位&quot;</strong>（Units）标签页</li></ol><h4 id="方法二-快捷键打开-推荐新手使用" tabindex="-1">方法二：快捷键打开（推荐新手使用） <a class="header-anchor" href="#方法二-快捷键打开-推荐新手使用" aria-label="Permalink to “方法二：快捷键打开（推荐新手使用）”">​</a></h4><ol><li>启动 <strong>World Editor.exe</strong></li><li>直接在键盘上按下 <strong>F6</strong> 键</li><li>瞬间即可打开对象编辑器，直接进入单位编辑界面</li></ol><blockquote><p><strong>💡 新手提示</strong>：快捷键F6是最快的方式，建议新手记住这个按键。它在编辑地图时使用频率非常高。</p></blockquote><h3 id="编辑器界面布局详解" tabindex="-1">编辑器界面布局详解 <a class="header-anchor" href="#编辑器界面布局详解" aria-label="Permalink to “编辑器界面布局详解”">​</a></h3><p>打开单位编辑器后，你会看到一个包含多个区域的窗口：</p><table tabindex="0"><thead><tr><th>区域</th><th>名称</th><th>作用</th></tr></thead><tbody><tr><td>左上</td><td>分类列表</td><td>切换&quot;单位&quot;、&quot;物品&quot;、&quot;技能&quot;等不同类型[^2]</td></tr><tr><td>中部</td><td>单位列表</td><td>显示当前地图中所有的单位</td></tr><tr><td>右侧</td><td>属性面板</td><td>显示选中单位的所有可修改属性</td></tr></tbody></table><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常在左侧分类栏误选了&quot;物品&quot;或&quot;技能&quot;标签，然后在右侧属性面板找不到想要的设置。请一定确认左上角选择的是 <strong>&quot;单位&quot;</strong> 标签页。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>✅ 使用菜单或F6快捷键打开单位编辑器</li><li>✅ 在界面左侧找到&quot;单位&quot;分类</li><li>✅ 认识单位列表和属性面板的位置</li></ul><p>你已经完成了单位编辑器的基础入门！在下一节《单位属性详解》中，我们将学习如何修改一个单位的生命值、攻击力等具体属性。</p><h2 id="单位基础属性设置" tabindex="-1">单位基础属性设置 <a class="header-anchor" href="#单位基础属性设置" aria-label="Permalink to “单位基础属性设置”">​</a></h2><p>本节我们将学习如何在<strong>对象编辑器</strong>中为单位设置生命值、魔法值、攻击力、护甲等核心战斗属性。学完本节后，你将能够为你的RPG地图创建具有不同强度和特点的单位。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><h4 id="_1-打开对象编辑器" tabindex="-1">1. 打开对象编辑器 <a class="header-anchor" href="#_1-打开对象编辑器" aria-label="Permalink to “1. 打开对象编辑器”">​</a></h4><ol><li>启动 Warcraft III World Editor[^3]</li><li>按下键盘上的 <strong>F4</strong> 键，或点击顶部菜单栏的 <strong>&quot;对象编辑器&quot;</strong> 按钮</li><li>在左侧分类中找到 <strong>&quot;单位&quot;</strong> 选项并点击展开</li><li>选中你想要编辑的单位（可以是预设单位或你自己创建的单位）</li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你是第一次打开对象编辑器，左侧列表会显示很多预设单位。建议先用搜索功能（Ctrl+F）找到你需要的单位，这样更快捷！</p></blockquote><h4 id="_2-配置生命值与魔法值" tabindex="-1">2. 配置生命值与魔法值 <a class="header-anchor" href="#_2-配置生命值与魔法值" aria-label="Permalink to “2. 配置生命值与魔法值”">​</a></h4><p>在对象编辑器的右侧面板中，找到以下字段进行设置：</p><ol><li><strong>生命值</strong> — 找到 &quot;生命值（生命）&quot; 字段，点击数值并输入你想要的数字（例如 500、1000）</li><li><strong>魔法值</strong> — 找到 &quot;魔法值（魔法）&quot; 字段，设置单位的最大蓝量（例如 200、300）</li><li><strong>生命恢复速度</strong> — 找到 &quot;生命恢复&quot; 字段，决定单位每秒恢复多少生命</li><li><strong>魔法恢复速度</strong> — 找到 &quot;魔法恢复&quot; 字段，决定单位每秒恢复多少魔法</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手把生命值设置得非常高（比如 99999），但忘记了这样会让战斗变得毫无挑战。合理的设计是让玩家的英雄通过升级来逐步提升生命值！</p></blockquote><h4 id="_3-设置攻击力与攻击参数" tabindex="-1">3. 设置攻击力与攻击参数 <a class="header-anchor" href="#_3-设置攻击力与攻击参数" aria-label="Permalink to “3. 设置攻击力与攻击参数”">​</a></h4><p>在同一面板中继续找到攻击相关属性：</p><ol><li><strong>基础攻击力</strong> — 找到 &quot;伤害骰数量&quot; 和 &quot;伤害骰面数&quot;，这两个数值相乘就是单次攻击的基础伤害</li><li><strong>攻击间隔</strong> — 找到 &quot;攻击间隔&quot; 字段，数值越低攻击越快（默认 2.0 表示每秒攻击 0.5 次）</li><li><strong>攻击范围</strong> — 找到 &quot;攻击范围&quot; 字段，近战单位通常设置为 128，远距离单位可以根据需要设置更大数值</li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你想做一个远程法师单位，记得同时把 &quot;攻击类型&quot; 改成 &quot;魔法&quot; 或 &quot;英雄&quot; 类型，这样攻击会按法术伤害计算！</p></blockquote><h4 id="_4-配置护甲类型与护甲值" tabindex="-1">4. 配置护甲类型与护甲值 <a class="header-anchor" href="#_4-配置护甲类型与护甲值" aria-label="Permalink to “4. 配置护甲类型与护甲值”">​</a></h4><p>继续在面板中查找护甲相关设置：</p><ol><li><strong>护甲值</strong> — 找到 &quot;护甲&quot; 字段，输入数值（0-30 范围内比较合理）</li><li><strong>护甲类型</strong> — 找到 &quot;护甲类型&quot; 下拉菜单，可以选择 &quot;重甲&quot;、&quot;轻甲&quot;、&quot;英雄&quot;、&quot;无甲&quot; 等不同类型</li><li>护甲值越高，单位受到的物理伤害越少[^4]</li></ol><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的单位应该已经具备了基本的战斗属性。你现在可以为一只小怪设置较低的生命值和攻击力，为一个精英BOSS设置超高的生命值和强力攻击。记住，好的RPG设计是让不同单位有明显的强弱对比，让玩家在战斗中感受到成长和挑战！</p><h2 id="移动与路径设置" tabindex="-1">移动与路径设置 <a class="header-anchor" href="#移动与路径设置" aria-label="Permalink to “移动与路径设置”">​</a></h2><p>本节将教你如何在单位编辑器中设置单位的移动方式和碰撞属性。完成学习后，你将能够创建可以行走在地面、飞行或漂浮在不同地形上的单位，并正确调整它们的体积大小。</p><h3 id="移动类型详解-地面、飞行、漂浮" tabindex="-1">移动类型详解（地面、飞行、漂浮） <a class="header-anchor" href="#移动类型详解-地面、飞行、漂浮" aria-label="Permalink to “移动类型详解（地面、飞行、漂浮）”">​</a></h3><p>在 Warcraft III 中，不同的单位有各自的移动方式，这决定了它们能去哪里、不能去哪里。[^4]</p><ol><li><p><strong>第一步：打开单位编辑器</strong> — 启动 World Editor 后，按 <code>F4</code> 键打开&quot;对象编辑器&quot;（Object Editor），然后在左侧找到&quot;单位&quot;（Units）选项[^4]</p></li><li><p><strong>第二步：选择或创建单位</strong> — 选中你要设置移动方式的单位，或者按 <code>Ctrl + N</code> 创建一个新单位</p></li><li><p><strong>第三步：找到移动类型字段</strong> — 在单位属性面板中，向下滚动找到&quot;移动 - 速度&quot;（Movement - Speed）和&quot;移动 - 类型&quot;（Movement - Type）两个字段[^1]</p></li><li><p><strong>第四步：选择移动类型</strong> — 点击&quot;移动 - 类型&quot;下拉菜单，你会看到三种主要选项：</p><ul><li><strong>地面（Ground）</strong>：单位只能在地形上行走，会被树木和悬崖阻挡</li><li><strong>飞行（Fly）</strong>：单位在空中飞行，可以越过大多数障碍物和水面</li><li><strong>漂浮（Float）</strong>：单位可以漂浮在水面上，也可以像地面单位一样在陆地上移动</li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你的单位需要同时在水面和陆地行走，选择&quot;漂浮&quot;而不是&quot;飞行&quot;。飞行单位默认会在空中，不会下降到地面与你互动。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记设置移动速度。默认速度可能太慢（像普通农民走路一样），记得把&quot;移动 - 速度&quot;数值调整到 270-350 之间，这样单位才会移动得比较自然。[^1]</p></blockquote><h3 id="碰撞体积与占据面积" tabindex="-1">碰撞体积与占据面积 <a class="header-anchor" href="#碰撞体积与占据面积" aria-label="Permalink to “碰撞体积与占据面积”">​</a></h3><p>碰撞体积决定了一个单位占用多少空间，以及其他单位能否从它旁边挤过去。[^4]</p><ol><li><p><strong>第一步：找到碰撞体积字段</strong> — 在单位属性中，找到&quot;碰撞体积 - 施放&quot;（Collision Size）字段，单位是数字（通常是 16、24、32、48 等）</p></li><li><p><strong>第二步：理解数字含义</strong> — 数字越大，单位占用的空间越多。对于英雄，建议设置为 32；对于小兵或召唤物，可以设置为 16-24</p></li><li><p><strong>第三步：找到占据面积字段</strong> — 找到&quot;占据面积&quot;（Footprint）相关设置，这里决定了单位在地图上占据的网格数量</p></li><li><p><strong>第四步：设置合理的占据面积</strong> — 大型单位（如坦克、战争古树）需要更大的占据面积；普通单位通常使用默认的 1x1 格子</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果两个单位都需要占据同一个位置（比如一个单位站在另一个单位身上），你可能需要修改&quot;可攻击区域&quot;或使用触发器来调整。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上设置后，你的单位应该能够按照你选择的移动方式在地图上移动了。记住：<strong>地面单位</strong>被障碍阻挡，<strong>飞行单位</strong>无视大部分地形，<strong>漂浮单位</strong>可以过河。碰撞体积设置得太大可能导致单位卡住，设置得太小又会让单位看起来&quot;穿透&quot;其他东西。</p><blockquote><p><strong>💡 新手提示</strong>：创建完单位后，建议在地图上测试一下它的移动方式，确保它不会卡在悬崖边缘或穿过你不希望它通过的地方。可以在&quot;测试&quot;菜单中选择&quot;测试地图&quot;（Test Map）来快速验证。</p></blockquote><h2 id="技能与攻击配置" tabindex="-1">技能与攻击配置 <a class="header-anchor" href="#技能与攻击配置" aria-label="Permalink to “技能与攻击配置”">​</a></h2><p>本节将教你如何在单位编辑器中为单位配置攻击伤害、技能参数以及攻击时的视觉效果。完成学习后，你能让一个普通小兵变成会发射魔法弹的远程攻击者。</p><h3 id="基础攻击设置与武器音效" tabindex="-1">基础攻击设置与武器音效 <a class="header-anchor" href="#基础攻击设置与武器音效" aria-label="Permalink to “基础攻击设置与武器音效”">​</a></h3><ol><li><p><strong>打开单位编辑器</strong> — 在World Editor主界面按 <strong>F6</strong> 打开&quot;对象编辑器&quot;[^2]，或者点击顶部菜单 <strong>编辑 → 对象编辑器</strong>。这里可以修改所有单位和单位的属性。</p></li><li><p><strong>找到你的单位</strong> — 在左侧列表中展开&quot;单位&quot;选项，找到你要修改的单位（比如&quot;食尸鬼&quot;或&quot;步兵&quot;），点击选中它[^4]。</p></li><li><p><strong>设置基础伤害</strong> — 在右侧属性面板中找到 <strong>&quot;攻击 1 - 伤害骰&quot;</strong>（例如设为1）和 <strong>&quot;攻击 1 - 伤害面数&quot;</strong>（例如设为6）。伤害计算公式是：最小伤害=骰数，最大伤害=骰数×面数。如果设为1个6面骰，伤害就是1-6点随机值。</p></li><li><p><strong>调整攻击间隔与范围</strong> — 找到 <strong>&quot;攻击 1 - 攻击间隔&quot;</strong> 设置攻击速度（数值越大，攻击越慢），找到 <strong>&quot;攻击 1 - 范围&quot;</strong> 设置攻击距离。远程单位通常需要将范围设为500以上。</p></li><li><p><strong>配置武器音效</strong> — 展开 <strong>&quot;攻击 1 - 武器声音&quot;</strong> 下拉菜单，选择武器音效（如&quot;武器-挥舞-弓&quot;、&quot;武器-挥舞-剑&quot;等）。音效能让玩家感受到攻击的真实感[^1]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：同一个单位可以有两套攻击配置！Attack 1和Attack 2分别对应不同的攻击模式，比如近战+远程双形态。</p></blockquote><h3 id="弹道模型与攻击特效" tabindex="-1">弹道模型与攻击特效 <a class="header-anchor" href="#弹道模型与攻击特效" aria-label="Permalink to “弹道模型与攻击特效”">​</a></h3><ol><li><p><strong>设置弹道模型</strong> — 在属性面板中找到 <strong>&quot;艺术 - 弹道模型&quot;</strong> 字段。对于远程攻击单位，点击右侧按钮选择一个弹道文件（如&quot;Abilities\\Weapons\\Arrow\\Arrow.mdl&quot;是普通弓箭）。不设置弹道模型的话，远程攻击会没有飞行的视觉效果。</p></li><li><p><strong>调整弹道速度</strong> — 找到 <strong>&quot;攻击 1 - 弹道速度&quot;</strong> 参数，数值表示飞行速度（默认值约800）。数值越高，弹道飞行越快；数值太低会显得攻击软绵绵的。</p></li><li><p><strong>配置命中特效</strong> — 在 <strong>&quot;攻击 1 - 命中特效&quot;</strong> 中选择击中目标时播放的特效（如火焰、冰霜、毒液等）。这个设置让攻击不仅有伤害数值，还有视觉反馈。</p></li><li><p><strong>设置投射物弧度</strong> — 对于弓箭等抛射物，可以在 <strong>&quot;弹道模型&quot;</strong> 中选择带有弧线轨迹的模型，或者通过修改 <strong>&quot;弹道发射角度&quot;</strong> 调整抛物线弧度。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手只设置了伤害数值，却忘记给远程单位配置&quot;弹道模型&quot;，导致单位明明在攻击，但看不见任何飞行物。检查方法：进入游戏测试，远程单位发射时应该能看到飞行物从起点飞向目标。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上配置后，你的单位应该具备：可自定义的伤害数值、合适的攻击速度与范围、听到的武器音效，以及远程攻击时可见的飞行弹道和命中特效。建议先用一只&quot;弓箭手&quot;小兵练习所有步骤，确认弹道和音效都正常工作后再应用到正式单位上[^3]。</p><h2 id="高级设置与调试技巧" tabindex="-1">高级设置与调试技巧 <a class="header-anchor" href="#高级设置与调试技巧" aria-label="Permalink to “高级设置与调试技巧”">​</a></h2><p>本节将介绍单位编辑器中几个进阶功能——<strong>分类标签</strong>、<strong>自定义数据</strong>和<strong>调试方法</strong>。学完这些技巧，你就能更灵活地管理大量单位，并快速定位和解决游戏中的问题，让你的地图更专业、更稳定。</p><h3 id="单位分类与标签系统" tabindex="-1">单位分类与标签系统 <a class="header-anchor" href="#单位分类与标签系统" aria-label="Permalink to “单位分类与标签系统”">​</a></h3><p>当你创建了几十个甚至上百个单位后，如何快速找到它们？标签系统就是为此设计的[^4]。</p><ol><li><strong>第一步：打开对象编辑器</strong> — 在顶部菜单栏点击“对象编辑器”（Object Editor），或直接按 <strong>F6</strong> 快捷键打开[^2]</li><li><strong>第二步：选择单位类型</strong> — 在左侧列表中找到你想要分类的单位，点击选中它</li><li><strong>第三步：设置分类标签</strong> — 在右侧面板中找到“分类”（Art - Classification）选项，可以看到“大型”、“中型”、“小型”等体型分类，以及“机械”、“英雄”、“建筑”等类型标签</li><li><strong>第四步：添加自定义标签</strong> — 切换到“高级”（Advanced）标签页，找到“自定义值”（Custom Value）下方的“标签”（Valid Target）选项，点击添加自定义字符串标签，如“敌人”“友军”“NPC”等</li></ol><blockquote><p><strong>💡 新手提示</strong>：标签的真正威力在于<strong>触发器</strong>中使用！比如你可以设置所有带“boss”标签的单位拥有特殊技能，在触发器里只需一条条件判断 <code>单位拥有标签(unit, &quot;boss&quot;)</code> 就能批量处理。</p></blockquote><h3 id="自定义值-user-data-的妙用" tabindex="-1">自定义值（User Data）的妙用 <a class="header-anchor" href="#自定义值-user-data-的妙用" aria-label="Permalink to “自定义值（User Data）的妙用”">​</a></h3><p>每个单位都有4个“自定义值”字段（Custom Value 0-3），你可以理解为<strong>给单位贴的便利贴</strong>——用来存储任意数字信息，供触发器读取和修改。</p><ol><li><strong>第一步：设置自定义值</strong> — 在对象编辑器中选中单位，在右侧面板的“高级”标签页中，找到“自定义值 0-3”（Custom Value），输入你想要的数字，比如“1”代表等级、“100”代表金币奖励</li><li><strong>第二步：在触发器中读取</strong> — 打开触发器编辑器（Ctrl+F4），新建触发器，添加“单位生命周期”事件，然后在条件中添加 <code>整数 比较 (获取单位自定义值(unit, 0)) 等于 1</code> 来判断单位等级</li><li><strong>第三步：动态修改自定义值</strong> — 使用“设置单位自定义值”动作，可以在游戏中实时改变单位的属性标记</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易把“自定义值”和“属性值”搞混。自定义值<strong>不会</strong>直接影响单位的攻击力、生命值等属性，它只是一个<strong>存储空间</strong>，需要你用触发器主动读取并赋予意义。</p></blockquote><h3 id="测试与快速调试方法" tabindex="-1">测试与快速调试方法 <a class="header-anchor" href="#测试与快速调试方法" aria-label="Permalink to “测试与快速调试方法”">​</a></h3><p>地图做了一半，怎么知道效果对不对？World Editor 提供了内置的测试功能[^3]。</p><ol><li><strong>第一步：保存地图</strong> — 按 <strong>Ctrl+S</strong> 保存当前工作，这是测试前的必要步骤！</li><li><strong>第二步：进入测试模式</strong> — 点击顶部工具栏的绿色三角▶按钮（或按 <strong>F10</strong>），编辑器会自动启动 Warcraft III 并加载当前地图</li><li><strong>第三步：使用调试输出</strong> — 在触发器中添加“游戏记录 - 显示消息到屏幕”动作，设置一条提示语如“单位XXX已创建”，运行游戏时你就能看到这条消息</li><li><strong>第四步：即时修改</strong> — 测试过程中如果发现触发器有问题，可以直接在编辑器中修改，保存后按 <strong>F10</strong> 重新加载地图，无需退出游戏</li></ol><blockquote><p><strong>💡 新手提示</strong>：善用“游戏记录”输出调试信息，比反复试玩找bug高效十倍！建议在每个关键触发器开头都加一条打印语句，确认触发器是否被正确执行。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上三个部分的学习后，你应该掌握了：</p><ul><li>✅ 使用<strong>分类标签</strong>批量管理单位</li><li>✅ 利用<strong>自定义值</strong>存储和读取单位特殊信息</li><li>✅ 通过<strong>测试模式</strong>和<strong>调试输出</strong>快速定位问题</li></ul><p>这些技巧是成为专业地图作者的必经之路，多练习几次就能熟练运用！</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://en.wikipedia.org/wiki/Warcraft_III:_Reign_of_Chaos" target="_blank" rel="noreferrer">Warcraft III: Reign of Chaos - Wikipedia</a> — accessed 2026-05-08 [^2]: <a href="https://www.youtube.com/watch?v=fYdtgSdYw3E" target="_blank" rel="noreferrer">How to create a hero with custom models in Warcraft III World Editor</a> — accessed 2026-05-08 [^3]: <a href="https://world-editor-tutorials.thehelper.net/" target="_blank" rel="noreferrer">Warcraft III World Editor, Warcraft III Map Making Tutorials, Warcraft...</a> — accessed 2026-05-08 [^4]: <a href="https://warcraft.wiki.gg/wiki/Warcraft_III_World_Editor" target="_blank" rel="noreferrer">Warcraft III World Editor - Warcraft Wiki - Your wiki guide to the...</a> — accessed 2026-05-08</p>',82)])])}const c=o(l,[["render",n]]);export{q as __pageData,c as default};
